"use strict";
/* =====================================================================
 * content/destiny-peace.js —— 命运线【岁月静好 peace】
 * 母题：太爷爷说「打工是不可能打工的」。别人听出的是不甘与较劲，你听出的
 *       却是另一层意思——既然这条路这么累，那就不上了。不争不抢，把日子
 *       过舒坦，活过七十岁、身子骨硬朗、心里头敞亮，也是一种赢。这是老
 *       祖宗那句话的第三种答案：躺平不是认输，是看破之后的从容。
 * 五幕脊柱（确定性、按阶段推进，前幕选择在后幕/清算回收；晚年戏份更重）：
 *   1 序·看破     19岁  看透内卷，主动不上那条拼命的赛道
 *   2 起·旁人的眼光 27岁  同龄人都在拼，被催促攀比说没出息：裹挟 vs 守节奏 vs 自我怀疑
 *   3 折·重新入场的诱惑 35岁 暴富机会/家人施压，动心下场 vs 婉拒守心（两层分支）
 *   4 危·与自己和解 45岁  中年回望，怀疑这辈子是不是错了（两层分支）
 *   5 巅·晚年回望   58岁  晚年盘点「我赢了吗」，温柔收束，读 mood/health/age + 伏笔
 * 记录抉择用 dstChoose(s, chId, key, note)；回收用 dstPick / has(s,"dst_pick_*")。
 * ===================================================================== */
(function () {

  // —— 综合「内心的安宁度」：决定关键判定，越高越「静好」 ——
  function peacePower(s) {
    const st = s.stats || {};
    return (st.insight || 0) * 1.2 + (s.mood || 0) * 0.4 + (s.health || 0) * 0.3
         - (s.stress || 0) * 0.3;
  }

  registerDestiny("peace",
    {
      name: "岁月静好", motif: "打工是不可能打工的",
      acts: ["序·看破", "起·旁人的眼光", "折·诱惑", "危·和解", "巅·回望"],
      // —— 母题清算：回收一生的命运抉择 ——
      reckon: function (s) {
        // 真正「静好达成」：活过 70，且心情、健康都好
        const serene = s.age >= 70 && (s.mood || 0) > 60 && (s.health || 0) > 50;
        // 一生是否守住了本心（关键伏笔）
        const heldHeart = has(s, "dst_pick_peace_ownpace") || has(s, "dst_pick_peace_declined")
                        || has(s, "dst_pick_peace_letgo") || has(s, "dst_pick_peace_smalljoy");
        const wavered = has(s, "dst_pick_peace_pulled") || has(s, "dst_pick_peace_dived")
                      || has(s, "dst_pick_peace_dwell");
        if (serene && heldHeart) {
          return "你活过了七十岁，身子骨还算硬朗，心里头一片敞亮。一辈子没争过什么，也就没什么放不下的。"
            + "太爷爷那句「打工是不可能打工的」，你没去反驳，也没去较劲——你只是给它续了第三种答案："
            + "不上那条拼命的赛道，把寻常日子过出滋味，原来才是最难、也最赢的活法。这一局，你赢得安安静静。";
        }
        if (serene) {
          return "你到底是活过了七十岁，身子还撑得住，心境也算平和。只是夜深时偶尔会想起，"
            + "中途自己也曾被裹挟、被诱惑动摇过。好在兜兜转转，终究还是踱回了这条慢路上。"
            + "结局是好的——你赢了，只是这份从容，是磕磕绊绊才修来的。";
        }
        if (heldHeart) {
          return "你守了一辈子的本心，不争不抢，把日子过得很轻。可身子骨或心境到底没能两全，"
            + "没能稳稳活到那个圆满的年岁。但你这一程走得舒坦、活得明白——"
            + "「静好」二字，你信了一辈子，也活出了大半。这就不算输。";
        }
        if (wavered) {
          return "你曾想躺平，把日子过舒坦，可半道上还是被旁人的眼光、被翻身的诱惑一次次拽了下场。"
            + "争来争去，到头来既没争出个名堂，也没能守住当初那份清净。"
            + "「岁月静好」四个字，你向往了一辈子，却像隔着一层玻璃，始终没能真正握在手里。";
        }
        return "你这辈子想过得轻松些，可命运和心境都没能成全。"
          + "那条不争不抢的慢路，你认得，却没能一直走下去——遗憾，但你试着温柔地活过，这就够了。";
      }
    },
    [

      /* ========== 第1幕 序·看破（19岁）：主动不上赛道 ========== */
      {
        id: "dst_peace_1", at: { minAge: 19, stage: ["youth"] },
        title: "🍃 十九岁，你看破了那场没有尽头的赛跑",
        text: (s) => byClass(s, {
          poor: "同学们挤破头去争实习、刷绩点、卷证书，像一群追着自己尾巴跑的人。你出身寒微，本该比谁都拼命——可你越看越清醒：这条赛道再怎么拼，前面还有更狠的人。太爷爷那句「打工是不可能打工的」，旁人听着是不甘，你却咂摸出一丝别的味道：既然这么累，何必非要往里挤？日子，是用来过的，不是用来拼的。",
          mid: "宿舍熄灯后，室友还在刷题、改简历、计算着哪条路能多赚两千。你躺在床上，忽然觉得很累——一种还没开始就已经厌倦的累。太爷爷常念叨「打工是不可能打工的」，你头一回觉得，这话里藏着一条没人走的岔路：不争第一，不抢风头，把一辈子过得舒坦，难道就不是一种活法？",
          rich: "家里早给你铺好了路，你却连那条路也懒得急着走。看着同龄人为了一个名额面红耳赤，你只觉得没必要。太爷爷那句「打工是不可能打工的」，到你这儿成了底气十足的潇洒：有这份从容打底，何苦把自己绑上那台永不停歇的跑步机？人生苦短，先把日子过松快了再说。"
        }),
        choices: [
          { label: "断舍离：主动退出竞争，过简单清爽的日子", effect: (s) => {
              add(s, "mood", 8); add(s, "stress", -10); add(s, "insight", 3);
              return dstChoose(s, "dst_peace_1", "peace_optout",
                "你给自己定了调：不和任何人比，不追任何风口。需要的不多，想要的更少。把生活做减法，心反而越来越敞亮——这是你递给世界的第一份「不参与」。");
            } },
          { label: "向内求：少向外争，多把时间留给自己", effect: (s) => {
              add(s, "insight", 5); add(s, "mood", 5); add(s, "stress", -6);
              return dstChoose(s, "dst_peace_1", "peace_optout",
                "你不再问「怎么才能赢过别人」，开始问「我到底想怎么活」。读闲书、看落日、和自己待着。向外争是无底洞，向内求才有尽头——你早早把方向调了个个儿。");
            } },
          { label: "慢慢来：找份养得活自己的轻活就够了", effect: (s) => {
              add(s, "mood", 4); add(s, "stress", -8); add(s, "health", 3);
              return dstChoose(s, "dst_peace_1", "peace_optout",
                "你没想着大富大贵，只求一份饿不着、也累不垮的活计。剩下的力气，全留给生活本身。你信的是：能稳稳当当过一辈子，本就是顶难的本事。");
            } }
        ]
      },

      /* ========== 第2幕 起·旁人的眼光（27岁）：被裹挟 vs 守节奏 ========== */
      {
        id: "dst_peace_2", at: { minAge: 27 },
        title: "👀 二十七岁，所有人都在替你着急",
        text: (s) => {
          const optout = dstPick(s, "dst_peace_1") === "peace_optout";
          return (optout
            ? "这些年你过得不紧不慢，自己挺自在。可同龄人一个个买房、升职、晒娃，"
            : "二十七岁，正是被催着「上进」的年纪。同龄人一个个买房、升职、晒娃，")
            + "亲戚饭桌上指着你问「怎么还这样」，老同学半是关心半是优越地说你「没出息」。一时间，旁人的眼光像潮水一样涌过来。你那份安宁，第一次被外界摇得有点晃。";
        },
        choices: [
          { label: "被裹挟：算了，还是回去和大家一样拼吧", effect: (s) => {
              add(s, "stress", 12); add(s, "mood", -8); add(s, "network", 4);
              return dstChoose(s, "dst_peace_2", "peace_pulled",
                "你扛不住那一道道眼光，咬咬牙又挤回了那条赛道。重新开始加班、攀比、焦虑。你告诉自己这叫「成熟」，可只有夜里那口长叹知道，你把什么东西弄丢了。");
            } },
          { label: "守节奏：他们过他们的，我过我的", effect: (s) => {
              add(s, "mood", 10); add(s, "insight", 4); add(s, "stress", -6);
              return dstChoose(s, "dst_peace_2", "peace_ownpace",
                "你笑笑，不解释。买房升职是他们的节奏，慢悠悠把日子过香是你的节奏——没有哪条更高级。守住自己的步调，比追上别人的步调难得多，可你做到了。");
            } },
          { label: "自我怀疑：嘴上不认，心里却开始打鼓", next: (s) => ({
              text: "白天你还能云淡风轻地挡回去，可深夜独处时，那些话像针一样一根根扎回来：「我是不是真的错了？」「等老了会不会后悔？」你第一次对自己选的路，生出了动摇。怎么熬过这一关？",
              choices: [
                { label: "找个清静地方走走，让心自己沉淀下来", effect: (s) => {
                    add(s, "insight", 5); add(s, "mood", 6); add(s, "stress", -8); add(s, "health", 3);
                    return dstChoose(s, "dst_peace_2", "peace_ownpace",
                      "你没急着找答案，只是去山里、海边走了几天。看够了天高水阔，那点动摇自己就散了。你重新确认：怕的不是没出息，是临死前发现自己从没为自己活过。心，又定了。");
                  } },
                { label: "越想越慌，干脆也去随大流投了几份简历", effect: (s) => {
                    add(s, "stress", 10); add(s, "mood", -4); add(s, "network", 3);
                    return dstChoose(s, "dst_peace_2", "peace_pulled",
                      "怀疑像藤蔓一样缠上来。你松了口，偷偷投起简历、报起班，想着「随个大流总没错」。安宁出现了第一道裂缝——你还没察觉，自己已经悄悄上了别人的船。");
                  } }
              ]
            }) }
        ]
      },

      /* ========== 第3幕 折·重新入场的诱惑（35岁）：暴富/施压 ========== */
      {
        id: "dst_peace_3", at: { minAge: 35 },
        title: "💰 三十五岁，一个能让你「翻身」的机会找上门",
        text: (s) => {
          const pulled = dstPick(s, "dst_peace_2") === "peace_pulled";
          return "一个老同学风风火火地找来，说有个项目稳赚不赔，拉你一起干，三五年就能财务自由；"
            + "家里那头也施了压，催你买房、成家、「活得像个正经人」。"
            + (pulled ? "这两年你本就有点动摇，这下心里那团火被一下子点着了。"
                      : "面对这泼天的诱惑和层层的压力，你那颗本已平静的心，第一次被搅得翻江倒海。")
            + "下场搏一把，还是守住这份来之不易的清净？";
        },
        choices: [
          { label: "动心下场：拼一把，万一真翻身了呢", next: (s) => ({
              text: "你被说动了，把积蓄掏出来、把日子调成了战斗模式：早出晚归，应酬、算计、提心吊胆。久违的肾上腺素回来了，那份慢悠悠的安宁，也悄悄退了场。",
              choices: [
                { label: "全押进去，赌一个一夜翻身", effect: (s) => {
                    const win = rnd(0.32 + peacePower(s) / 600 + luckBias(s));
                    add(s, "stress", 16); add(s, "health", -8); add(s, "mood", -4);
                    if (win) { add(s, "cash", 200000); add(s, "mood", 6); bumpMomentum(s, 8); }
                    else { add(s, "cash", -80000); add(s, "mood", -10); bumpMomentum(s, -8); }
                    return dstChoose(s, "dst_peace_3", "peace_dived",
                      win ? "项目侥幸成了，你账户里多了一笔钱。可那段拼命的日子，你掉了头发、丢了睡眠、和家人也疏远了。钱是赚到了，那份「静好」却像漏了气的气球——你开始怀念从前的轻。"
                          : "项目黄了，积蓄打了水漂。你忙活一场，赔了钱，还赔上了好几年的安稳觉。镜子里那个焦虑的中年人，你都快不认得了。早知如此，何必当初。");
                  } },
                { label: "试着踩一脚刹车，给自己留条退路", effect: (s) => {
                    add(s, "stress", 8); add(s, "insight", 3); add(s, "mood", 2);
                    return dstChoose(s, "dst_peace_3", "peace_dived",
                      "你下了场，却没敢把命搭进去——留了底、控了量。结果不算大赚，也没伤筋动骨。这趟下来你想明白一件事：原来自己根本不享受这种刺激，下次说什么也不来了。");
                  } }
              ]
            }) },
          { label: "婉拒守心：谢谢，但我这样就挺好", next: (s) => ({
              text: "你笑着把同学的酒杯满上，把那番宏图大业听完，然后轻轻摇了头。回到家，面对家人的不解和叹气，你也只是温和而坚定地说：我知道你们为我好，可我真的不想要那种活法。",
              choices: [
                { label: "诚恳地跟家人摊开心里话，求一份理解", effect: (s) => {
                    add(s, "mood", 8); add(s, "insight", 4); add(s, "network", 3); add(s, "stress", -4);
                    return dstChoose(s, "dst_peace_3", "peace_declined",
                      "你花了一整晚，第一次认认真真把自己的人生观讲给家人听。他们未必全懂，但看见了你的笃定。守心不等于不顾旁人——你既挡住了诱惑，也没把亲情推远。这份分寸，难得。");
                  } },
                { label: "不多解释，用日子过得好不好来回应", effect: (s) => {
                    add(s, "mood", 6); add(s, "stress", -8); add(s, "health", 4); add(s, "insight", 3);
                    return dstChoose(s, "dst_peace_3", "peace_declined",
                      "你不争辩，只是把自己的小日子过得越来越有滋味：阳台种满了花，灶上熬着汤，周末去爬山。时间久了，连最爱念叨你的亲戚都没话说了——活得舒坦，本身就是最好的回答。");
                  } }
              ]
            }) }
        ]
      },

      /* ========== 第4幕 危·与自己和解（45岁）：内心的风暴 ========== */
      {
        id: "dst_peace_4", at: { minAge: 45 },
        title: "🌧️ 四十五岁，一场只在你心里下的雨",
        text: (s) => {
          const dived = dstPick(s, "dst_peace_3") === "peace_dived";
          return "人到中年，一个寻常的深夜，你忽然被一阵巨大的空落攫住。"
            + (dived ? "当年那场折腾留下的疲惫还没散尽，你愈发分不清：自己到底想要什么。"
                     : "曾经一起的人有的发了财，有的当了官，朋友圈里全是热闹。")
            + "「我这大半辈子，是不是过错了？」「这么平淡地活着，到底有没有意义？」——这是你与自己最较劲的一场风暴。";
        },
        dynamicChoices: (s) => ([
          { label: "钻牛角尖：反复盘算自己「亏」了多少", effect: (s) => {
              add(s, "stress", 14); add(s, "mood", -12); add(s, "health", -5);
              return dstChoose(s, "dst_peace_4", "peace_dwell",
                "你陷进去了，一遍遍拿自己和别人比，越比越亏，越想越苦。那些「如果当初」像潮水一样把你淹没。这场雨下了很久很久——安宁不是没来过，是你自己把它推开了。");
            } },
          { label: "真正释怀：放下「应该」，与自己和解", next: (s) => ({
              text: "你逼着自己停下那场没完没了的比较。你翻出年轻时的日记，看见那个早早就想明白「为自己活」的少年。你忽然鼻子一酸——这些年的轻松、健康、那些被你认真过过的清晨与黄昏，难道都不算数吗？",
              choices: [
                { label: "把这些年的好，一笔一笔认真记下来", effect: (s) => {
                    add(s, "mood", 14); add(s, "insight", 6); add(s, "stress", -14); add(s, "health", 4);
                    return dstChoose(s, "dst_peace_4", "peace_letgo",
                      "你列了一张清单：睡到自然醒的早晨、说走就走的旅行、没透支过的身体、没出卖过的良心……写着写着你笑了。原来你从没亏，是「别人的成功」蒙了你的眼。雨停了，云开了，心透亮了。");
                  } },
                { label: "找老友长谈一夜，把心里的结说出来", effect: (s) => {
                    add(s, "mood", 10); add(s, "insight", 5); add(s, "network", 4); add(s, "stress", -10);
                    return dstChoose(s, "dst_peace_4", "peace_letgo",
                      "你约了多年的老友，喝着茶把憋了半生的话倒了出来。对方却说：「你知道我多羡慕你吗？」一句话点醒了你。原来你以为的「平庸」，是别人求而不得的从容。和解，往往就在被人看见的那一刻。");
                  } }
              ]
            }) },
          { label: "找小确幸：在最寻常的日子里安顿自己", effect: (s) => {
              add(s, "mood", 10); add(s, "health", 5); add(s, "stress", -10); add(s, "insight", 3);
              return dstChoose(s, "dst_peace_4", "peace_smalljoy",
                "你没去和那场风暴硬碰，只是转身去做了顿饭、浇了浇花、陪老人说了会儿话。一粥一饭，一草一木，把你一点点拉回地面。意义不在远方的大事里，就在这些微小而确实的幸福里。心，慢慢就稳了。");
            } }
        ])
      },

      /* ========== 第5幕 巅·晚年回望（58岁）：温柔收束 ========== */
      {
        id: "dst_peace_5", at: { minAge: 58 },
        title: "🌅 五十八岁，坐在自家阳台上盘点这一生",
        text: (s) => {
          const letgo = has(s, "dst_pick_peace_letgo") || has(s, "dst_pick_peace_smalljoy");
          if (letgo) {
            return "黄昏的光铺在阳台上，茶还温着。你靠在藤椅里，慢慢回想这一生——年轻时看破，中年时和解，没争过什么，也就没什么遗憾。「我赢了吗？」这个问题，今天你想认真给自己一个答复。";
          }
          return "夕阳把窗子染成暖橙色。退休的日子静得能听见钟摆。你坐着发了会儿呆，半生的画面一幕幕淌过心头。「我这一辈子，到底算不算赢？」——是时候和自己做个了断了。";
        },
        dynamicChoices: (s) => {
          const heldHeart = has(s, "dst_pick_peace_ownpace") || has(s, "dst_pick_peace_declined")
                          || has(s, "dst_pick_peace_letgo") || has(s, "dst_pick_peace_smalljoy");
          return [
            { label: "安心收下这份从容：把日子继续慢慢过下去", effect: (s) => {
                add(s, "mood", 16); add(s, "health", 8); add(s, "stress", -16); add(s, "insight", 4);
                if (heldHeart) { add(s, "mood", 6); add(s, "health", 4); }
                return dstChoose(s, "dst_peace_5", "peace_serene",
                  heldHeart
                    ? "你给了自己一个温柔的答复：赢了。不是赢过谁，是赢回了自己的一生——身子还硬朗，心里还敞亮，每一天都踏踏实实属于自己。「打工是不可能打工的」，你没去打谁的脸，只是安静地，把日子过成了别人羡慕的样子。"
                    : "你想了想，点了点头：这一程虽有起伏，可眼下身心都还安稳，已是福气。剩下的日子，你打定主意要好好过——不再被任何人的眼光牵着走。从容，是越晚越懂的本事。");
              } },
            { label: "把心得传下去：陪后辈聊聊「别那么拼也行」", effect: (s) => {
                add(s, "mood", 12); add(s, "insight", 6); add(s, "network", 5); add(s, "health", 4); add(s, "stress", -8);
                return dstChoose(s, "dst_peace_5", "peace_serene",
                  "后辈也撞上了你当年那堵「内卷」的墙，急得团团转。你沏上茶，把自己这一生的活法慢慢讲给他听：「钱够花、身子好、心里宽，就够了，真的。」你这条没人走的路，如今成了别人脚下的一束光。这份传承，比任何成就都让你心安。");
              } },
            { label: "也曾不甘：对没去拼的那些，认真道一次别", effect: (s) => {
                add(s, "mood", 6); add(s, "insight", 5); add(s, "stress", -6); add(s, "health", 2);
                return dstChoose(s, "dst_peace_5", "peace_serene",
                  "你坦诚地承认，午夜里也曾闪过「如果当年拼一把会怎样」的念头。但你没让这念头生根——你对那个没去争抢的人生，郑重地道了声别。和解不是没有遗憾，是带着遗憾依然觉得：这样，挺好。心口那块石头，落了地。");
              } }
          ];
        }
      }

    ]);

})();
